args.sparql:
SELECT ?event WHERE {
  ?event wdt:P361 wd:Q9680 ; # part of 2018 Winter Olympics
         wdt:P641 wd:Q5368 ; # sport curling
         wdt:P31/wdt:P279* wd:Q5671887 . # instance of curling competition or subclass
  ?event wdt:P512 wd:Q222208 . # men's event
}

SELECT DISTINCT ?event WHERE {
  ?event wdt:P361 wd:Q9680 ; # part of 2018 Winter Olympics
         wdt:P641 wd:Q5368 ; # sport curling
         wdt:P1532 wd:Q209597 . # gender = men's
}

SELECT ?event WHERE {
  ?event wdt:P361 wd:Q9680 ; # part of 2018 Winter Olympics
         wdt:P641 wd:Q5368 ; # sport curling
         wdt:P2521 wd:Q209597 . # sport discipline: men's event
}

SELECT ?winner WHERE {
  ?event wdt:P361 wd:Q9680 ; # part of 2018 Winter Olympics
         wdt:P1344 wd:Q15497591 . # men's curling discipline
  ?event p:P1923 [ ps:P1923 ?winner ;
                   pq:P4100 wd:Q11660 ] . # gold medal
}

SELECT DISTINCT ?winner ?winnerLabel WHERE {
  ?event wdt:P361 wd:Q9680 ;
         wdt:P641 wd:Q5368 ;
         wdt:P2506 wd:Q209597 .
  ?event p:P1923 [ ps:P1923 ?winner ;
                   pq:P4100 wd:Q11660 ] .
  OPTIONAL { ?winner rdfs:label ?winnerLabel . FILTER (lang(?winnerLabel) = 'en') }
}

SELECT ?event ?eventLabel WHERE {
  ?event wdt:P361 wd:Q9680 .
  ?event rdfs:label ?eventLabel .
  FILTER (CONTAINS(LCASE(?eventLabel), "men's curling")) .
  FILTER (LANG(?eventLabel) = 'en') .
}

